const items = $input.all();
const out = [];
for (const item of items) {
  const j = item.json || {};
  const stdout = String(j.stdout || '');
  const stderr = String(j.stderr || j.error?.message || j.message || '');
  const code = j.code !== undefined ? Number(j.code) : 1;
  let manifest = null;
  const m = stdout.match(/BACKUP_MANIFEST_JSON=(\{.*\})\s*$/m)
    || stdout.match(/BACKUP_MANIFEST_JSON=(\{.*\})/);
  if (m) {
    try { manifest = JSON.parse(m[1]); } catch (_) { manifest = null; }
  }
  const redact = (s) => String(s || '')
    .replace(/postgres(?:ql)?:\/\/[^\s'"]+/gi, 'postgres://***')
    .replace(/(password|passwd|pwd)\s*[:=]\s*\S+/gi, '$1=***')
    .replace(/service[_-]?role[_-]?key\s*[:=]\s*\S+/gi, 'service_role_key=***')
    .replace(/Bearer\s+[A-Za-z0-9._\-]+/gi, 'Bearer ***');
  const redactedOut = redact(stdout).slice(-2000);
  const redactedErr = redact(stderr).slice(-1500);
  const status = manifest?.status || (code === 0 ? 'ok' : 'failed');
  const size = manifest?.size_bytes;
  const minBytes = Number($env.BACKUP_MIN_BYTES || 10240);
  const reasons = [];
  if (code !== 0 || status === 'failure' || status === 'failed') reasons.push('backup_or_watchdog_failed');
  if (size !== undefined && size !== null && Number(size) < minBytes) reasons.push('backup_too_small');
  if (String(manifest?.error || '').includes('checksum') || String(manifest?.error || '').includes('gzip_integrity')) {
    reasons.push('checksum_failure');
  }
  if (/oci os object|oci_upload_failed|destination/i.test(redactedErr + redactedOut + String(manifest?.error || ''))) {
    reasons.push('destination_failure');
  }
  if (/BACKUP_WATCHDOG_STATUS=(missing|stale)/.test(stdout)) reasons.push('missed_schedule');
  const ts = manifest?.timestamp_utc || manifest?.timestamp || new Date().toISOString();
  const message = [
    'Vergeo5 DB backup ALERT',
    `status=${status}`,
    `exit_code=${code}`,
    `reasons=${reasons.join(',') || 'unspecified'}`,
    `env=${manifest?.env_id || 'n/a'}`,
    `dump=${manifest?.dump_name || 'n/a'}`,
    `size_bytes=${size ?? 'n/a'}`,
    `sha256=${manifest?.sha256 ? String(manifest.sha256).slice(0, 12) + '…' : 'n/a'}`,
    `migration_tip=${manifest?.migration_tip || 'n/a'}`,
    `ts=${ts}`,
    'stderr_tail:',
    redactedErr || '(empty)',
  ].join('\n');
  out.push({ json: { message, status, code, reasons, manifest, stdout_tail: redactedOut } });
}
return out;

