const e = $input.first().json || {};
const msg = String(e.execution?.error?.message || e.message || 'workflow_error');
const safe = msg
  .replace(/postgres(?:ql)?:\/\/[^\s'"]+/gi, 'postgres://***')
  .replace(/(password|passwd|pwd)\s*[:=]\s*\S+/gi, '$1=***')
  .replace(/Bearer\s+[A-Za-z0-9._\-]+/gi, 'Bearer ***')
  .slice(0, 800);
return [{ json: { message: `Vergeo5 DB backup WORKFLOW ERROR\n${safe}` } }];
